Hi,
  Maybe a known limitation, trying named association in function call does not seem to work. below is a test and error:

IVL 12.0 devel version.

> ../ivl_i389.sv:19: syntax error
> ../ivl_i389.sv:19: error: malformed statement

Code below.

Thanks
Srini

```verilog
package test_pkg;

  virtual class uvm_void;
  endclass : uvm_void

  class uvm_object extends uvm_void;
    function new (string name = "uvm_object");
    endfunction : new 

    virtual function void print ();
      $display ("Print");
    endfunction : print 
  endclass : uvm_object

  class uvm_report_object extends uvm_object;
    string name = "uvm_report_object";
    // function new (string name = "uvm_report_object");
    function new ();
      super.new (.name (name));
      // super.new (name);
    endfunction : new 
  endclass : uvm_report_object 

endpackage : test_pkg

module m;
  import test_pkg::*;
  uvm_object u0;
  
   initial begin : test
     #100;
     $display ("Hello World");
     u0 = new ();
     u0.print();

   end : test

endmodule : m


```

